using System;
using UnityEngine;

namespace APTromboneChampMod;

public static class Base64Images
{
    // track collections
    
    private const string ICON_AP_FLAT = "";
    public static readonly Sprite ArchipelagoCollection = FromBase64(ICON_AP_FLAT, 200, 200);

    private const string ICON_AP_FILTER = "";
    public static readonly Sprite ArchipelagoCollectionFiltered = FromBase64(ICON_AP_FILTER, 200, 200);

    private const string ICON_AP_LOCKED = "";
    public static readonly Sprite ArchipelagoCollectionLocked = FromBase64(ICON_AP_LOCKED, 200, 200);

    // connection indicator
    
    private const string ICON_AP = "";
    public static readonly Sprite Archipelago = FromBase64(ICON_AP, 40, 40);

    private const string ICON_AP_GREY = "";
    public static readonly Sprite ArchipelagoGrey = FromBase64(ICON_AP_GREY, 40, 40);

    // hot dog indicator

    private const string HOT_DOG = "";
    public static readonly Sprite HotDog = FromBase64(HOT_DOG, 40, 40);

    private const string HOT_DOG_GREY = "";
    public static readonly Sprite HotDogGrey = FromBase64(HOT_DOG_GREY, 40, 40);
    
    // rank indicator

    private const string RANK = "";
    public static readonly Sprite RankIndicator = FromBase64(RANK, 40, 40);

    private const string RANK_GREY = "";
    public static readonly Sprite RankIndicatorGrey = FromBase64(RANK_GREY, 40, 40);
    
    // difficulty indicator

    private const string DIFF = "";
    public static readonly Sprite DifficultyIndicator = FromBase64(DIFF, 40, 40);
    
    private const string DIFF_GREY = "";
    public static readonly Sprite DifficultyIndicatorGrey = FromBase64(DIFF_GREY, 40, 40);

    
    private static Sprite FromBase64(string b64, int width, int height)
    {
        byte[] imageBytes = Convert.FromBase64String(b64);
        Texture2D tex = new Texture2D(width, height);
        tex.LoadImage(imageBytes);
        return Sprite.Create(tex, new Rect(0f, 0f, width, height), new Vector2(0.5f, 0.5f));
    }
}